        memcpy(&newPlayer.name, packet->data, sizeof(packet->data));
        newPlayer.position = {0, 0, 0};
        newPlayer.rotation = {0, 0, 0};
        newPlayer.health = 100;
        newPlayer.score = 0;
        newPlayer.address = clientAddr;
        newPlayer.active = true;
        newPlayer.lastUpdate = packet->timestamp;
        
        players[playerId] = newPlayer;
        
        Packet response;
